parameters.functionCode:
/*
Expected POST body:
{
  userId: "user_123",
  pickedAt?: ISO,
  items: [ { name, qty, unit, variety?, bed?, quality? } ],
  printLabels?: true|false,
  labelTemplateId?: string
}
*/
const b = items[0]?.json || {};
const apiBase = $env.SUKA_API_BASE || 'http://localhost:4000';

function normArray(x){ return Array.isArray(x)? x: (x? [x]: []); }
function iso(x){ try { return x? new Date(x).toISOString(): new Date().toISOString(); } catch { return new Date().toISOString(); } }
const userId = b.userId || null;
const pickedAt = iso(b.pickedAt);
const itemsIn = normArray(b.items).map((it,i)=>({
  name: it.name,
  qty: Number(it.qty || 0),
  unit: it.unit || '',
  variety: it.variety || null,
  bed: it.bed || null,
  quality: it.quality || 'good'
})).filter(x=>x.qty>0 && x.name);

// Simple preservation recommendation map
const MAP = [
  { test: /tomato/i, plan: (x)=> ({ method:'can', title:`Can tomatoes (${x.qty} ${x.unit})`, labels:[{ productName:'Canned Tomatoes', batchCode:null }] }) },
  { test: /cucumber/i, plan: (x)=> ({ method:'pickle', title:`Pickle cucumbers (${x.qty} ${x.unit})`, labels:[{ productName:'Pickles', batchCode:null }] }) },
  { test: /(pepper|chili)/i, plan: (x)=> ({ method:'freeze', title:`Chop & freeze peppers (${x.qty} ${x.unit})`, labels:[{ productName:'Frozen Peppers', batchCode:null }] }) },
  { test: /(berry|strawberry|blueberry|raspberry)/i, plan: (x)=> ({ method:'freeze', title:`Freeze berries (${x.qty} ${x.unit})`, labels:[{ productName:'Frozen Berries', batchCode:null }] }) },
  { test: /(basil|herb|mint|oregano|thyme|rosemary|sage|dill)/i, plan: (x)=> ({ method:'dehydrate', title:`Dehydrate herbs (${x.qty} ${x.unit})`, labels:[{ productName:'Dried Herbs', batchCode:null }] }) },
  { test: /(leaf|lettuce|spinach|greens|kale|chard)/i, plan: (x)=> ({ method:'blanch_freeze', title:`Blanch & freeze greens (${x.qty} ${x.unit})`, labels:[{ productName:'Frozen Greens', batchCode:null }] }) }
];

function recommend(it){
  const m = MAP.find(m => m.test.test(it.name));
  if (!m) return null;
  const rec = m.plan(it);
  return {
    ...rec,
    item: it,
    due: new Date(Date.now() + 6*60*60*1000).toISOString(), // later today
    priority: 2,
    labels: rec.labels || []
  };
}

const recs = itemsIn.map(recommend).filter(Boolean);

// Build label items
function batchCode(){ const d = new Date(); const y = d.getFullYear(); const m = String(d.getMonth()+1).padStart(2,'0'); const dd = String(d.getDate()).padStart(2,'0'); return `HARV-${y}${m}${dd}`; }
const code = batchCode();
const wantLabels = !!b.printLabels;
const labelTemplateId = b.labelTemplateId || null;
const labelItems = recs.flatMap(r => (r.labels || []).map(L => ({
  productName: L.productName || r.method,
  batchCode: L.batchCode || code,
  variety: r.item.variety || undefined,
  packedOn: new Date().toISOString().slice(0,10)
})));

// Inventory intake lines
const intakeLines = itemsIn.map(x => ({ name: x.name, qty: x.qty, unit: x.unit, source: 'garden', pickedAt }));

return [{ json: { apiBase, userId, pickedAt, items: itemsIn, recommendations: recs, intakeLines, wantLabels, labelItems, labelTemplateId } }];

const out = [];
for (const r of ($json.recommendations || [])) {
  out.push({ json: {
    title: `${r.title}`,
    category: 'preservation',
    labels: ['preservation', r.method, $json.pickedAt.slice(0,10)],
    priority: r.priority || 2,
    due: r.due,
    meta: { item: r.item, method: r.method },
    userId: $json.userId,
    apiBase: $json.apiBase
  }});
}
return out.length ? out : [{ json: { skip: true } }];

const ctx = items[0].json;
const summary = {
  ok: true,
  intake: ($items('HTTP: Inventory Intake', 0, 0)[0]?.json) || { ok: true },
  tasksCreated: ($items('HTTP: Create Preservation Task', 0, 0)?.length) || 0,
  labelsPrinted: ($items('HTTP: Print Labels', 0, 0)?.length) ? true : false,
  recommendations: (ctx.recommendations || []).length
};
return [{ json: summary }];

/* Expect server to return { userId?, pickedAt?, items:[...] } or an array */
const data = items[0]?.json || {};
const arr = Array.isArray(data) ? data : (Array.isArray(data.items) ? [data] : []);
if (!arr.length) return [{ json: { skip: true } }];
const out = [];
for (const b of arr) {
  out.push({ json: {
    userId: b.userId || null,
    pickedAt: b.pickedAt || new Date().toISOString(),
    items: b.items || [],
    printLabels: true,
    labelTemplateId: null
  }});
}
return out;
